package com.demo.web.dto.Settings;

public class SettingsProfileRequest { private Integer userId; private String username; private String bio; private String currentPassword; private String newPassword; private String confirmPassword; private String profilePictureUrl; private boolean fileUploaded; public SettingsProfileRequest(Integer userId, String username, String bio, String currentPassword, String newPassword, String confirmPassword, String profilePictureUrl, boolean fileUploaded) { this.userId = userId; this.username = username; this.bio = bio; this.currentPassword = currentPassword; this.newPassword = newPassword; this.confirmPassword = confirmPassword; this.profilePictureUrl = profilePictureUrl; this.fileUploaded = fileUploaded; } public Integer getUserId() { return userId; } public String getUsername() { return username; } public String getBio() { return bio; } public String getCurrentPassword() { return currentPassword; } public String getNewPassword() { return newPassword; } public String getConfirmPassword() { return confirmPassword; } public String getProfilePictureUrl() { return profilePictureUrl; } public boolean isFileUploaded() { return fileUploaded; } }
